// ── Build typed Product array ─────────────────────────────────────────────────
const NEW_THRESHOLD_MS = 30 * 24 * 60 * 60 * 1000; // 30 days
const NOW = new Date('2026-04-06').getTime();

export const products: Product[] = raw.map((row, idx): Product => {
  const [name, set, cardNumber, rarity, variance, condition, marketPrice, priceOverride, stock, dateAdded] = row;
  const isSealed = cardNumber === '';
  return {
    id: `pokemon-${idx}`,
    name,
    tcg: 'pokemon',
    set,
    cardNumber: isSealed ? undefined : cardNumber,
    rarity: rarity || undefined,
    variance: variance || undefined,
    condition: condition as CardCondition,
    price: priceOverride > 0 ? priceOverride : marketPrice,
    stock,
    category: (isSealed ? 'sealed' : 'single') as ProductCategory,
    isNew: NOW - new Date(dateAdded).getTime() <= NEW_THRESHOLD_MS,
    dateAdded,
  };
});

// ── Helpers ───────────────────────────────────────────────────────────────────
export const getProductById = (id: string) => products.find((p) => p.id === id);

export const getUniqueSets = (tcg?: string) =>
  [...new Set(products.filter((p) => !tcg || p.tcg === tcg).map((p) => p.set))].sort();

export const getUniqueRarities = (tcg?: string) =>
  [...new Set(products.filter((p) => !tcg || p.tcg === tcg).map((p) => p.rarity).filter(Boolean))].sort() as string[];
